import { useState, useEffect } from "react";
import axios from "axios";
import { useParams, useNavigate } from "react-router-dom";

const API = "https://team-task-manager-4-7vl7.onrender.com";

export default function Tasks() {
  const { projectId } = useParams();
  const navigate = useNavigate();

  const token = localStorage.getItem("token") || "";

  const [tasks, setTasks] = useState([]);
  const [form, setForm] = useState({
    title: "",
    description: "",
    dueDate: "",
    priority: "Medium",
  });

  // 🔄 LOAD TASKS
  useEffect(() => {
    if (projectId) {
      loadTasks();
    }
  }, [projectId]);

  // ✅ FIXED GET API + TOKEN
  const loadTasks = async () => {
    try {
      console.log("PROJECT ID:", projectId);

      const res = await axios.get(
        `${API}/api/tasks/project/${projectId}`,
        {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        }
      );

      setTasks(res.data);
    } catch (err) {
      console.error("GET TASK ERROR:", err);
      setTasks([]);
    }
  };

  // ✅ FIXED POST WITH TOKEN
  const createTask = async (e) => {
    e.preventDefault();

    try {
      await axios.post(
        `${API}/api/tasks`,
        {
          title: form.title,
          description: form.description,
          dueDate: form.dueDate,
          priority: form.priority,
          project: projectId,
        },
        {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        }
      );

      // clear form
      setForm({
        title: "",
        description: "",
        dueDate: "",
        priority: "Medium",
      });

      loadTasks();
    } catch (err) {
      console.error("CREATE ERROR:", err);
    }
  };

  return (
    <div style={styles.page}>
      {/* 🔙 BACK BUTTON */}
      <button style={styles.backBtn} onClick={() => navigate("/dashboard")}>
        ← Back to Dashboard
      </button>

      <h2 style={styles.title}>📋 Project Tasks</h2>

      {/* 🧾 FORM */}
      <form onSubmit={createTask} style={styles.form}>
        <input
          placeholder="Title"
          value={form.title}
          onChange={(e) =>
            setForm({ ...form, title: e.target.value })
          }
          required
          style={styles.input}
        />

        <input
          placeholder="Description"
          value={form.description}
          onChange={(e) =>
            setForm({ ...form, description: e.target.value })
          }
          style={styles.input}
        />

        <input
          type="date"
          value={form.dueDate}
          onChange={(e) =>
            setForm({ ...form, dueDate: e.target.value })
          }
          style={styles.input}
        />

        <select
          value={form.priority}
          onChange={(e) =>
            setForm({ ...form, priority: e.target.value })
          }
          style={styles.input}
        >
          <option>Low</option>
          <option>Medium</option>
          <option>High</option>
        </select>

        <button type="submit" style={styles.btn}>
          Create Task
        </button>
      </form>

      <hr />

      {/* 📦 TASK LIST */}
      {tasks.length === 0 ? (
        <p>No tasks yet</p>
      ) : (
        tasks.map((t) => (
          <div key={t._id} style={styles.card}>
            <h4>{t.title}</h4>
            <p>{t.description}</p>
            <p>Status: {t.status}</p>
            <p>Priority: {t.priority}</p>
          </div>
        ))
      )}
    </div>
  );
}

const styles = {
  page: {
    padding: 20,
    background: "#f4f6f7",
    minHeight: "100vh",
  },

  title: {
    marginBottom: 20,
  },

  form: {
    background: "white",
    padding: 15,
    borderRadius: 10,
    marginBottom: 20,
  },

  input: {
    display: "block",
    width: "100%",
    padding: 10,
    marginBottom: 10,
    borderRadius: 6,
    border: "1px solid #ddd",
  },

  btn: {
    background: "#27AE60",
    color: "white",
    padding: 10,
    border: "none",
    borderRadius: 6,
    cursor: "pointer",
  },

  card: {
    background: "white",
    padding: 10,
    borderRadius: 8,
    marginBottom: 10,
  },

  backBtn: {
    marginBottom: 15,
    padding: "6px 10px",
    border: "1px solid #333",
    background: "transparent",
    cursor: "pointer",
  },
};
